module RefModule(datain, dataout, load, hold, clock);
input [4:0] datain;
input load, hold;
input clock;
output [4:0] dataout;
reg [4:0] obf_out;
always @(posedge clock)
begin
    if(load)
       obf_out <= datain;
    else if(hold)
       obf_out <= obf_out;
    else
       obf_out <= 5'b0;
end
assign dataout = obf_out;
endmodule
